defmodule WebhookProxyWeb.ProxyController do
  use WebhookProxyWeb, :controller

  def fetch_content(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, %HTTPoison.Response{status_code: 200, body: body}} ->
        conn
        |> put_status(:ok)
        |> json(%{content: body})

      {:ok, %HTTPoison.Response{status_code: status_code, body: body}} ->
        conn
        |> put_status(status_code)
        |> json(%{error: "Failed to fetch content", details: body})

      {:error, %HTTPoison.Error{reason: reason}} ->
        conn
        |> put_status(:bad_request)
        |> json(%{error: "Invalid URL or network error", details: inspect(reason)})
    end
  end
end